template <int N, class F>
static double benchmark(F&& fn) {
  double best = 1e100;
  for (int i = 0; i < N; ++i) {
    double t = fn();
    if (t < best) best = t;
  }
  return best;
}

static void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

static void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}

static void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}

static void show_progress_done(void) { flushed_printf("\n"); }

template <typename T>
__device__ __forceinline__ T op_add(T a, T b) { return a + b; }

template <typename T>
__device__ __forceinline__ T op_mul(T a, T b) { return a * b; }

__device__ __forceinline__ __half2 op_add(__half2 a, __half2 b) { return __hadd2(a, b); }
__device__ __forceinline__ __half2 op_mul(__half2 a, __half2 b) { return __hmul2(a, b); }

template <typename T>
__device__ __forceinline__ bool op_equal(T a, T b) { return a == b; }

__device__ __forceinline__ bool op_equal(__half2 a, __half2 b) {
  return (__half2float(__low2half(a)) == __half2float(__low2half(b))) &&
         (__half2float(__high2half(a)) == __half2float(__high2half(b)));
}

template <typename T>
__device__ __forceinline__ T op_zero();

template <>
__device__ __forceinline__ int op_zero<int>() { return 0; }
template <>
__device__ __forceinline__ float op_zero<float>() { return 0.0f; }
template <>
__device__ __forceinline__ double op_zero<double>() { return 0.0; }
template <>
__device__ __forceinline__ short op_zero<short>() { return 0; }
template <>
__device__ __forceinline__ __half2 op_zero<__half2>() { return __float2half2_rn(0.0f); }

template <typename T>
__device__ __forceinline__ T op_neg_one();

template <>
__device__ __forceinline__ int op_neg_one<int>() { return -1; }
template <>
__device__ __forceinline__ float op_neg_one<float>() { return -1.0f; }
template <>
__device__ __forceinline__ double op_neg_one<double>() { return -1.0; }
template <>
__device__ __forceinline__ short op_neg_one<short>() { return -1; }
template <>
__device__ __forceinline__ __half2 op_neg_one<__half2>() { return __float2half2_rn(-1.0f); }

template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_func(T seed, T* g_data) {
  const unsigned int blockSize = blockDim.x;
  int stride, idx;
  if (BLOCK_STRIDED) {
    stride = (int)blockSize;
    idx = (int)blockIdx.x * (int)blockSize * ELEMENTS_PER_THREAD + (int)threadIdx.x;
  } else {
    const int grid_size = (int)blockSize * (int)gridDim.x;
    stride = grid_size;
    idx = (int)blockIdx.x * (int)blockDim.x + (int)threadIdx.x;
  }
  const int big_stride = (int)gridDim.x * (int)blockSize * ELEMENTS_PER_THREAD;

  T tmps[ELEMENTS_PER_THREAD];
  for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = op_add(op_mul(tmps[j], tmps[j]), seed);
      }
    }

    T sum = op_zero<T>();
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = op_add(sum, op_mul(tmps[j], tmps[j + 1]));
    }

    if (op_equal(sum, op_neg_one<T>())) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}

#define CASE_CI(CI, T, EPT, FD, BS) \
  case CI: benchmark_func<T, CI, EPT, FD, BS><<<blocks, threads>>>(seed, data); break

template <typename T, int EPT, int FD, bool BS>
static void launch_for_ci(int ci, T seed, T* data, int blocks, int threads) {
  switch (ci) {
    CASE_CI(0, T, EPT, FD, BS);   CASE_CI(1, T, EPT, FD, BS);
    CASE_CI(2, T, EPT, FD, BS);   CASE_CI(3, T, EPT, FD, BS);
    CASE_CI(4, T, EPT, FD, BS);   CASE_CI(5, T, EPT, FD, BS);
    CASE_CI(6, T, EPT, FD, BS);   CASE_CI(7, T, EPT, FD, BS);
    CASE_CI(8, T, EPT, FD, BS);   CASE_CI(9, T, EPT, FD, BS);
    CASE_CI(10, T, EPT, FD, BS);  CASE_CI(11, T, EPT, FD, BS);
    CASE_CI(12, T, EPT, FD, BS);  CASE_CI(13, T, EPT, FD, BS);
    CASE_CI(14, T, EPT, FD, BS);  CASE_CI(15, T, EPT, FD, BS);
    CASE_CI(16, T, EPT, FD, BS);  CASE_CI(17, T, EPT, FD, BS);
    CASE_CI(18, T, EPT, FD, BS);  CASE_CI(20, T, EPT, FD, BS);
    CASE_CI(22, T, EPT, FD, BS);  CASE_CI(24, T, EPT, FD, BS);
    CASE_CI(28, T, EPT, FD, BS);  CASE_CI(32, T, EPT, FD, BS);
    CASE_CI(40, T, EPT, FD, BS);  CASE_CI(48, T, EPT, FD, BS);
    CASE_CI(56, T, EPT, FD, BS);  CASE_CI(64, T, EPT, FD, BS);
    CASE_CI(80, T, EPT, FD, BS);  CASE_CI(96, T, EPT, FD, BS);
    CASE_CI(128, T, EPT, FD, BS); CASE_CI(192, T, EPT, FD, BS);
    CASE_CI(256, T, EPT, FD, BS);
    default: break;
  }
}

template <typename LaunchFn>
static double timed_launch(LaunchFn&& launch, bool use_os_timer) {
  if (use_os_timer) {
    auto ts_start = std::chrono::high_resolution_clock::now();
    launch();
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
    auto ts_end = std::chrono::high_resolution_clock::now();
    std::chrono::duration<double, std::milli> ms = ts_end - ts_start;
    return ms.count();
  } else {
    cudaEvent_t ev_start, ev_stop;
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start));
    launch();
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
    return (double)ms;
  }
}

static void runbench_warmup(double* d_buffer, long size, size_t workgroupsize) {
  const long reduced_grid_size = size / 256;
  const int threads = (int)workgroupsize;
  const int blocks = (int)(reduced_grid_size / (long)threads);
  short seed = 1;
  launch_for_ci<short, 1, 1, false>(0, seed, reinterpret_cast<short*>(d_buffer), blocks, threads);
  CUDA_SAFE_CALL(cudaGetLastError());
}

static void runbench(const int compute_iterations[],
                     unsigned int krn_idx,
                     double* d_buffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool block_strided,
                     bool use_os_timer,
                     bool enable_dp,
                     bool enable_hp) {
  const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (elements_per_wi * (long long)compute_grid_size +
       (2 * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
      fusion_degree;
  const long long memoryoperations = size;

  const int threads = (int)workgroupsize;
  const int blocks = (int)(compute_grid_size / (long)threads);
  constexpr int total_bench_iterations = 3;

  double kernel_time_mad_sp = benchmark<total_bench_iterations>([&]() {
    const float seed_f = 1.0f;
    double t = timed_launch([&]() {
      if (block_strided) {
        launch_for_ci<float, 8, 4, true>(current_compute_iterations, seed_f,
                                         reinterpret_cast<float*>(d_buffer), blocks, threads);
      } else {
        launch_for_ci<float, 8, 4, false>(current_compute_iterations, seed_f,
                                          reinterpret_cast<float*>(d_buffer), blocks, threads);
      }
      CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);
    return t;
  });

  double kernel_time_mad_dp = benchmark<total_bench_iterations>([&]() {
    if (!enable_dp) return 0.0;
    const double seed_d = 1.0;
    return timed_launch([&]() {
      if (block_strided) {
        launch_for_ci<double, 8, 4, true>(current_compute_iterations, seed_d,
                                          reinterpret_cast<double*>(d_buffer), blocks, threads);
      } else {
        launch_for_ci<double, 8, 4, false>(current_compute_iterations, seed_d,
                                           reinterpret_cast<double*>(d_buffer), blocks, threads);
      }
      CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);
  });

  double kernel_time_mad_hp = benchmark<total_bench_iterations>([&]() {
    if (!enable_hp) return 0.0;
    const __half2 seed_h = __float2half2_rn(1.0f);
    return timed_launch([&]() {
      if (block_strided) {
        launch_for_ci<__half2, 8, 4, true>(current_compute_iterations, seed_h,
                                           reinterpret_cast<__half2*>(d_buffer), blocks, threads);
      } else {
        launch_for_ci<__half2, 8, 4, false>(current_compute_iterations, seed_h,
                                            reinterpret_cast<__half2*>(d_buffer), blocks, threads);
      }
      CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);
  });

  double kernel_time_mad_int = benchmark<total_bench_iterations>([&]() {
    const int seed_i = 1;
    return timed_launch([&]() {
      if (block_strided) {
        launch_for_ci<int, 8, 4, true>(current_compute_iterations, seed_i,
                                       reinterpret_cast<int*>(d_buffer), blocks, threads);
      } else {
        launch_for_ci<int, 8, 4, false>(current_compute_iterations, seed_i,
                                        reinterpret_cast<int*>(d_buffer), blocks, threads);
      }
      CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) /
          ((double)memoryoperations * sizeof(__half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
          1000. / (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

static void mixbenchGPU_impl(double* c,
                             long size,
                             bool block_strided,
                             bool host_allocated,
                             bool use_os_timer,
                             size_t workgroupsize,
                             unsigned int elements_per_wi,
                             unsigned int fusion_degree) {
  const char* benchtype = block_strided ? "Workgroup" : "NDRange";
  printf("Workitem stride:        %s\n", benchtype);
  const char* buffer_allocation =
      host_allocated ? "Host allocated" : "Device allocated";
  printf("Buffer allocation:      %s\n", buffer_allocation);
  printf("Timer:                  %s\n",
         use_os_timer ? "OS based" : "CL event based");

  cudaDeviceProp prop = GetDeviceProperties();
  bool enable_dp = (prop.major > 1) || (prop.major == 1 && prop.minor >= 3);
  if (!enable_dp)
    printf(
        "Warning:                Double precision computations are not "
        "supported\n");
  bool enable_hp = IsFP16Supported();
  if (!enable_hp)
    printf(
        "Warning:                Half precision computations are not "
        "supported\n");

  double* d_buffer = nullptr;
  void* host_mapped_ptr = nullptr;

  if (host_allocated) {
    CUDA_SAFE_CALL(cudaSetDeviceFlags(cudaDeviceMapHost));
    CUDA_SAFE_CALL(cudaHostAlloc(&host_mapped_ptr, size * sizeof(double), cudaHostAllocMapped));
    CUDA_SAFE_CALL(cudaHostGetDevicePointer((void**)&d_buffer, host_mapped_ptr, 0));
  } else {
    CUDA_SAFE_CALL(cudaMalloc((void**)&d_buffer, size * sizeof(double)));
  }

  CUDA_SAFE_CALL(cudaMemset(d_buffer, 0, size * sizeof(int)));

  printf("Loading kernel source file...\n");
  printf("Precompilation of kernels... ");
  show_progress_init(compute_iterations_len);
  for (int i = 0; i < compute_iterations_len; i++) {
    show_progress_step(0, '\\');
    show_progress_step(0, '|');
    if (enable_dp) show_progress_step(0, '/');
    if (enable_hp) show_progress_step(0, '-');
    show_progress_step(1, '>');
  }
  show_progress_done();

  if (elements_per_wi != 8 || fusion_degree != 4) {
    fprintf(stderr, "Error: Unsupported elements_per_wi/fusion_degree in CUDA translation.\n");
    exit(EXIT_FAILURE);
  }

  runbench_warmup(d_buffer, size, workgroupsize);
  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  printf(
      "----------------------------------------------------------------------------- CSV data "
      "-----------------------------------------------------------------------------"
      "-----\n");
  printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, d_buffer, size, workgroupsize,
             elements_per_wi, fusion_degree, block_strided, use_os_timer,
             enable_dp, enable_hp);
  }

  printf(
      "-----------------------------------------------------------------------------------------------------------------------------"
      "--------------------\n");

  if (host_allocated) {
    memcpy(c, host_mapped_ptr, size * sizeof(double));
    CUDA_SAFE_CALL(cudaFreeHost(host_mapped_ptr));
  } else {
    CUDA_SAFE_CALL(cudaMemcpy(c, d_buffer, size * sizeof(double), cudaMemcpyDeviceToHost));
    CUDA_SAFE_CALL(cudaFree(d_buffer));
  }
}

extern "C" void mixbenchGPU(double* c, long size) {
  const bool block_strided = false;
  const bool host_allocated = false;
  const bool use_os_timer = false;
  const size_t workgroupsize = 256;
  const unsigned int elements_per_wi = 8;
  const unsigned int fusion_degree = 4;

  mixbenchGPU_impl(c, size, block_strided, host_allocated, use_os_timer,
                   workgroupsize, elements_per_wi, fusion_degree);
}
